import{_ as t,o,c as a,a0 as i}from"./chunks/framework.Bmhw_dvp.js";const m=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),s={name:"guide/architecture.md"};function n(d,e,r,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>The adaptation loop runs entirely on the client/runtime side. Adaptive MCP is a learning layer over MCP primitives — it does not replace MCP, redefine tools, or introduce new protocol abstractions.</p><h2 id="the-loop" tabindex="-1">The loop <a class="header-anchor" href="#the-loop" aria-label="Permalink to &quot;The loop&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ToolExec[&quot;Tool execution (MCP server)&quot;] --&gt; Telemetry</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Telemetry --&gt;|records event| Memory[&quot;MemoryStore (SQLite SSOT)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Memory --&gt; Eval[&quot;Evaluation&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Eval --&gt;|insights| Memory</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Telemetry --&gt; Ext[&quot;ExtensionController&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Memory --&gt; Ext</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Eval --&gt; Ext</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Ext --&gt;|reads SSOT| YAML[&quot;tools-metadata.yaml (derived view)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Ext --&gt; Resource[&quot;MCP resource: dev.adaptivemcp/tools-metadata&quot;]</span></span></code></pre></div><p>Data always flows in one direction: <strong>event → MemoryStore (SSOT) → derived YAML view</strong>. The YAML is never edited directly; it is recomputed from the SSOT whenever metadata changes.</p><h2 id="design-constraints" tabindex="-1">Design constraints <a class="header-anchor" href="#design-constraints" aria-label="Permalink to &quot;Design constraints&quot;">​</a></h2><ul><li><strong>MCP sets the contract; Adaptive MCP learns the behavior.</strong> MCP answers <em>&quot;what can the model do?&quot;</em>; Adaptive MCP answers <em>&quot;what have we learned about how those capabilities are actually used?&quot;</em> and turns that into metadata, not new primitives.</li><li><strong>Enrich, don&#39;t replace.</strong> No first-class <code>adaptiveTool</code>, <code>adaptiveSkill</code>, <code>adaptiveIntent</code>, or <code>adaptiveWorkflow</code> concepts. Adaptive MCP operates on MCP primitives (tools, resources) as intentional boundaries.</li><li><strong>Avoid coupling to implementation details.</strong> Packages must not depend on shell, filesystem paths, processes, sockets, or HTTP as first-class concepts. Those remain implementation details of the host.</li><li><strong>Middleware is operational machinery.</strong> Telemetry, evaluation, memory, routing, and approval exist to observe, evaluate, remember, route, and recommend. Business logic belongs in middleware packages; the client stays thin.</li><li><strong>Stateless servers, accumulating clients.</strong> MCP servers are lightweight and replaceable. Clients accumulate knowledge in a local source of truth.</li></ul><h2 id="relationship-to-mcp" tabindex="-1">Relationship to MCP <a class="header-anchor" href="#relationship-to-mcp" aria-label="Permalink to &quot;Relationship to MCP&quot;">​</a></h2><blockquote><p><strong>Unofficial project.</strong> Adaptive MCP is an independent, personal experiment. It is <strong>not</strong> affiliated with, endorsed by, or maintained by the Model Context Protocol project, its stewards, or any vendor. The <code>dev.adaptivemcp/</code> extension namespace is a reversed-domain identifier of the project domain (<code>adaptivemcp.dev</code>) and is used in the spirit of, but not as part of, any official MCP extension.</p></blockquote><p>The <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a> is an open standard that lets applications provide context and capabilities (tools, resources, prompts) to language models in a uniform way. Adaptive MCP builds on MCP rather than beside or beneath it. It does not fork, extend, or replace the protocol; it observes how MCP tools are actually used and attaches learned metadata (annotations, insights, recommendations) to the <strong>existing</strong> MCP primitives.</p><ul><li>MCP servers stay standard and stateless; Adaptive MCP adds a client-side learning loop and a single derived resource (<code>dev.adaptivemcp/tools-metadata</code>) that a server <em>may</em> publish to <strong>govern</strong> tool adaptation.</li><li>The pattern is a server-governed resource that clients read and report against, degrading gracefully on any host that ignores it. The draft proposal lives at <a href="https://github.com/kemalelmizan/adaptive-mcp/blob/main/docs/sep-2133-tools-metadata.md" target="_blank" rel="noreferrer"><code>docs/sep-2133-tools-metadata.md</code></a>.</li></ul><h2 id="data-model" tabindex="-1">Data model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data model&quot;">​</a></h2><p>All metadata is persisted in a SQLite store (<code>node:sqlite</code>). The schema is a single <code>tools</code> table keyed by <code>tool_name</code>:</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Contents</th></tr></thead><tbody><tr><td><code>tool_name</code></td><td>TEXT (PK)</td><td>Tool identifier</td></tr><tr><td><code>server_name</code></td><td>TEXT</td><td>Originating MCP server</td></tr><tr><td><code>annotation</code></td><td>JSON</td><td>Static, human-written <code>Annotation</code></td></tr><tr><td><code>insights</code></td><td>JSON</td><td>Learned <code>Insight[]</code></td></tr><tr><td><code>recommendations</code></td><td>JSON</td><td>Suggested <code>Recommendation[]</code></td></tr><tr><td><code>stats</code></td><td>JSON</td><td>Accumulated <code>ToolStats</code></td></tr><tr><td><code>updated_at</code></td><td>TEXT</td><td>ISO-8601 timestamp</td></tr></tbody></table><h3 id="core-types-adaptivemcp-spec" tabindex="-1">Core types (<code>@adaptivemcp/spec</code>) <a class="header-anchor" href="#core-types-adaptivemcp-spec" aria-label="Permalink to &quot;Core types (\`@adaptivemcp/spec\`)&quot;">​</a></h3><ul><li><strong><code>Annotation</code></strong>: static, human-authored metadata (<code>risk</code>, <code>owner</code>, <code>tags</code>, <code>description</code>). Never changes on its own.</li><li><strong><code>Insight</code></strong>: learned from observed behavior (<code>key</code>, <code>value</code>, <code>confidence</code>, <code>source</code> of <code>evaluation</code> or <code>telemetry</code>, <code>sampleSize</code>). Upserted by key.</li><li><strong><code>Recommendation</code></strong>: suggested adaptation (<code>type</code> of <code>model</code>, <code>approval</code>, <code>workflow</code>, or <code>routing</code>, plus <code>payload</code>, <code>rationale</code>, <code>confidence</code>). Written by the routing/orchestration/approval packages.</li><li><strong><code>ToolStats</code></strong>: <code>invocations</code>, <code>failures</code>, <code>failureRate</code>, <code>avgDurationMs</code>, <code>totalCost</code>, <code>lastObservedAt</code>. Folded from each execution event.</li><li><strong><code>ToolRecord</code></strong>: the aggregate row (<code>toolName</code>, <code>serverName</code>, <code>annotation</code>, <code>insights</code>, <code>recommendations</code>, <code>stats</code>, <code>updatedAt</code>).</li></ul><h3 id="derived-yaml-view-tools-metadata-yaml" tabindex="-1">Derived YAML view (<code>tools-metadata.yaml</code>) <a class="header-anchor" href="#derived-yaml-view-tools-metadata-yaml" aria-label="Permalink to &quot;Derived YAML view (\`tools-metadata.yaml\`)&quot;">​</a></h3><p>The <code>ExtensionController</code> projects each <code>ToolRecord</code> into a <code>ToolMetadataView</code> and serializes the document with <code>js-yaml</code>. The view is the machine- and human-readable projection consumed by out-of-band MCP clients.</p><h2 id="adaptation-behaviors" tabindex="-1">Adaptation behaviors <a class="header-anchor" href="#adaptation-behaviors" aria-label="Permalink to &quot;Adaptation behaviors&quot;">​</a></h2><ul><li><strong>Routing</strong> (<code>Router.routeTool</code>): picks the cheapest model meeting the observed latency/failure profile; emits a <code>routing</code> recommendation when a tool/server approaches or exceeds its cost budget (≥ 80% of limit).</li><li><strong>Orchestration</strong> (<code>Orchestrator.planTool</code>): when <code>failureRate ≥ flakyThreshold</code> (default 0.1), writes a <code>workflow</code> recommendation with a retry policy scaled to the failure rate (capped at <code>maxAttempts = 6</code>).</li><li><strong>Approval</strong> (<code>ApprovalGate.gate</code>): returns <code>deny</code> for denied tools, <code>require_confirmation</code> for high-risk annotations or flaky tools (failure rate ≥ <code>flakyFailureRate</code>, default 0.2, after <code>minInvocations</code>), else <code>allow</code>. Writes an <code>approval</code> recommendation with <code>payload: { decision }</code>.</li><li><strong>Thin client</strong> (<code>ThinClient.run</code>): consults the gate, then executes with the SSOT-derived retry policy (or default). Records the outcome back to the SSOT.</li></ul><h2 id="adaptiveruntime" tabindex="-1"><code>AdaptiveRuntime</code> <a class="header-anchor" href="#adaptiveruntime" aria-label="Permalink to &quot;\`AdaptiveRuntime\`&quot;">​</a></h2><p><code>AdaptiveRuntime</code> wires every package into a single transport-agnostic runtime:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tool call -&gt; telemetry -&gt; MemoryStore (SSOT) -&gt; evaluation -&gt; insights</span></span>
<span class="line"><span>                                                   -&gt; routing       -&gt; recommendations</span></span>
<span class="line"><span>                                                   -&gt; orchestration -&gt; recommendations</span></span>
<span class="line"><span>                                                   -&gt; approval      -&gt; gate + recommendation</span></span>
<span class="line"><span>                                                   -&gt; ExtensionController -&gt; YAML view</span></span></code></pre></div><p>This is the operational machinery; it is intentionally transport-agnostic.</p>`,24)])])}const u=t(s,[["render",n]]);export{m as __pageData,u as default};
